import{_ as e,o as t,c as a,g as s}from"./chunks/framework.CtuiYkcd.js";const h=JSON.parse('{"title":"一四七","description":"","frontmatter":{"title":"一四七","date":"2021-08-27T10:46:16.000Z","length":"160字","time":"1分钟","aside":false,"hash":-1915849295},"headers":[],"relativePath":"idea/147.md","filePath":"idea/147.md"}'),o={name:"idea/147.md"},n=s("p",null,"天下大乱，贤圣不明，道德不一。天下多得一察焉以自好。譬如耳目鼻口，皆有所明，不能相通。犹百家众技也，皆有所长，时有所用 。虽然，不该不遍，一曲之士也。判天地之美，析万物之理，察古人之全。寡能备于天地之美，称神明之容。是故内圣外王之道，暗而不明，郁而不发，天下之人各为其所欲焉以自为方。悲夫！百家往而不反，必不合矣！后世之学者，不幸不见天地之纯，古人之大体。道术将为天下裂。 ——《庄子·天下》",-1),r=[n];function c(d,i,_,l,p,m){return t(),a("div",null,r)}const u=e(o,[["render",c]]);export{h as __pageData,u as default};
